            ))}
            <div className="my-2 border-t border-white/10" />
            <button
              onClick={() => { setLocation('/audit'); setMobileOpen(false); }}
              className="w-full rounded-lg bg-[#C9A64A] py-2.5 text-sm font-semibold text-black"
