type Tab = 'overview' | 'intake' | 'briefs' | 'barristers' | 'fees' | 'diary';

export default function ClerkDashboard() {
  const [, setLocation] = useLocation();
  const [activeTab, setActiveTab] = useState<Tab>('overview');
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const [stats, setStats] = useState<Stats | null>(null);
  const [barristers, setBarristers] = useState<Barrister[]>([]);
  const [briefs, setBriefs] = useState<Brief[]>([]);
  const [diary, setDiary] = useState<DiaryEntry[]>([]);
  const [intakeForms, setIntakeForms] = useState<IntakeForm[]>([]);

  async function fetchAll(showRefreshing = false) {
    if (showRefreshing) setRefreshing(true);
    else setLoading(true);

    try {
      const [statsRes, barristersRes, briefsRes, diaryRes, intakeRes] = await Promise.all([
        fetch('/api/clerks/stats'),
        fetch('/api/clerks/barristers'),
        fetch('/api/clerks/briefs'),
        fetch('/api/clerks/diary'),
        fetch('/api/admin/intake-forms'),
      ]);

      if (statsRes.ok) setStats(await statsRes.json());
      if (barristersRes.ok) setBarristers(await barristersRes.json());
      if (briefsRes.ok) setBriefs(await briefsRes.json());
      if (diaryRes.ok) setDiary(await diaryRes.json());
      if (intakeRes.ok) setIntakeForms(await intakeRes.json());
    } catch {
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }

  useEffect(() => {
    fetchAll();
  }, []);

  function handleRefresh() {
    fetchAll(true);
  }

  async function convertIntakeToBrief(form: IntakeForm) {
    try {
      const res = await fetch('/api/clerks/briefs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          clientName: form.clientName,
          matterType: form.matterType,
          solicitorFirm: '',
          notes: form.description ?? '',
        }),
      });
      if (!res.ok) throw new Error();
      const brief = await res.json();
      toast.success(`Brief created: ${brief.briefRef}`);
      fetchAll(true);
    } catch {
      toast.error('Failed to create brief');
    }
  }

  const urgencyClass: Record<string, string> = {
    low: 'bg-gray-500/20 text-gray-400 border-gray-500/40',
    medium: 'bg-yellow-500/20 text-yellow-400 border-yellow-500/40',
    high: 'bg-orange-500/20 text-orange-400 border-orange-500/40',
    critical: 'bg-red-500/20 text-red-400 border-red-500/40',
  };

  const TABS: { id: Tab; label: string; icon: React.ElementType }[] = [
    { id: 'overview', label: 'Overview', icon: TrendingUp },
    { id: 'intake', label: `Intake Queue${intakeForms.length ? ` (${intakeForms.length})` : ''}`, icon: FileText },
    { id: 'briefs', label: 'Briefs', icon: FileText },
    { id: 'barristers', label: 'Barristers', icon: Users },
    { id: 'fees', label: 'Fees', icon: DollarSign },
    { id: 'diary', label: 'Diary', icon: Calendar },
  ];

  return (
    <div className="min-h-screen font-sans" style={{ backgroundColor: BG, color: 'white' }}>
      <SEO title="Clerk Dashboard" description="Law Clerks chambers management dashboard." />
      <h1 className="sr-only">Law Clerks — Chambers Management Dashboard</h1>
      {/* Top nav */}
      <nav
        className="sticky top-0 z-40 border-b backdrop-blur"
        style={{ borderColor: BORDER, backgroundColor: `${BG}E6` }}
      >
        <div className="mx-auto flex max-w-7xl items-center justify-between px-6 py-4">
          <div className="flex items-center gap-4">
            <button
              onClick={() => setLocation('/law-clerks')}
              className="flex items-center gap-1 text-sm text-gray-500 hover:text-gray-300 transition-colors"
            >
              <ChevronLeft className="h-4 w-4" />
              Back
            </button>
            <span className="text-lg font-bold" style={{ color: GOLD }}>
              Law Clerks
            </span>
            <span className="hidden text-gray-600 sm:inline">|</span>
            <span className="hidden text-sm text-gray-400 sm:inline">Chambers Dashboard</span>
          </div>
          <Button
            onClick={handleRefresh}
            disabled={refreshing}
            variant="outline"
            className="gap-2 border-[#1E2030] text-gray-400 hover:bg-white/5"
          >
            <RefreshCw className={`h-4 w-4 ${refreshing ? 'animate-spin' : ''}`} />
            <span className="hidden sm:inline">Refresh</span>
          </Button>
        </div>
      </nav>

      <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6">
        {/* Tab bar */}
        <div className="mb-8 flex gap-1 overflow-x-auto rounded-xl border p-1" style={{ borderColor: BORDER, backgroundColor: CARD_BG }}>
          {TABS.map(({ id, label, icon: Icon }) => (
            <button
              key={id}
              onClick={() => setActiveTab(id)}
              className="flex flex-shrink-0 items-center gap-2 rounded-lg px-4 py-2 text-sm font-medium transition-all"
              style={
                activeTab === id
                  ? { backgroundColor: GOLD, color: BG }
                  : { color: '#9CA3AF' }
              }
            >
              <Icon className="h-4 w-4" />
              {label}
            </button>
          ))}
        </div>

        {/* Content */}
        {loading ? (
          <PageSkeleton />
        ) : (
          <>
            {activeTab === 'intake' && (
              <IntakeQueueTab
                forms={intakeForms}
                urgencyClass={urgencyClass}
                onConvert={convertIntakeToBrief}
              />
            )}
            {activeTab === 'overview' && (
              <OverviewTab stats={stats} diary={diary} />
            )}
            {activeTab === 'briefs' && (
              <BriefsTab briefs={briefs} barristers={barristers} onRefresh={handleRefresh} />
            )}
            {activeTab === 'barristers' && (
              <BарristersTab barristers={barristers} onRefresh={handleRefresh} />
            )}
            {activeTab === 'fees' && (
              <FeesTab briefs={briefs} onRefresh={handleRefresh} />
            )}
            {activeTab === 'diary' && <DiaryTab briefs={briefs} />}
          </>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect, FormEvent } from 'react';
import { useLocation, useSearch } from 'wouter';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Loader2, CheckCircle, AlertCircle, ArrowLeft, FileText, ShieldCheck } from 'lucide-react';
import { toast } from 'sonner';
import MainNav from '@/components/MainNav';
import SEO from '@/components/SEO';

interface CompanyData {
  number: string;
  name: string;
  status: string;
  type?: string;
  incorporationDate?: string;
}

interface FilingDeadline {
  nextDue: string;
  daysUntilDue: number;
  overdue: boolean;
}

interface OverdueFiling {
  type: string;
  description: string;
  dueDate: string;
  daysOverdue: number;
  penaltyRisk: number;
}

interface Penalty {
  estimated: number;
  description: string;
}

interface ComplianceData {
  status: 'compliant' | 'warning' | 'overdue';
  riskLevel: 'none' | 'low' | 'medium' | 'high';
  accounts: FilingDeadline;
  confirmationStatement?: FilingDeadline;
  overdueFilings: OverdueFiling[];
  penalties?: Penalty[]; // Optional - only present if there are overdue filings
}

export default function ComplianceBundle() {
  const [, setLocation] = useLocation();
  const search = useSearch();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [bundleId, setBundleId] = useState('');
  const [companyData, setCompanyData] = useState<CompanyData | null>(null);
  const [complianceData, setComplianceData] = useState<ComplianceData | null>(null);
  const [error, setError] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [monitored, setMonitored] = useState(false);
  const [checkoutLoading, setCheckoutLoading] = useState(false);

  const [formData, setFormData] = useState({
    companyName: '',
    companyNumber: '',
    requestorName: '',
    requestorEmail: '',
    bundleType: 'full',
  });

  // Check protection status whenever we have a company number (including on Stripe return)
  useEffect(() => {
    if (!companyData?.number) return;

    fetch(`/api/protection-status?companyNumber=${encodeURIComponent(companyData.number)}`)
      .then((r) => r.json())
      .then((data) => {
        if (data.monitored) {
          setMonitored(true);
        }
      })
      .catch(() => {/* non-blocking */});
  }, [companyData?.number]);

  // Handle return from Stripe (?activated=1&company=...)
  useEffect(() => {
    const params = new URLSearchParams(search);
    if (params.get('activated') === '1') {
      const companyNumber = params.get('company');
      if (companyNumber) {
        fetch(`/api/protection-status?companyNumber=${encodeURIComponent(companyNumber)}`)
          .then((r) => r.json())
          .then((data) => {
            if (data.monitored) {
              setMonitored(true);
              toast.success('Protection activated — your company is now being monitored.');
            }
          })
          .catch(() => {/* non-blocking */});
      }
    }
  }, [search]);

  const handleActivate = async () => {
    if (!companyData) return;
    setCheckoutLoading(true);
    try {
      const response = await fetch('/api/stripe/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          companyNumber: companyData.number,
          companyName: companyData.name,
        }),
      });
      const data = await response.json();
      if (response.ok && data.url) {
        window.location.href = data.url;
      } else {
        toast.error(data.error || 'Could not start checkout. Please try again.');
      }
    } catch {
      toast.error('Network error. Please check your connection.');
    } finally {
      setCheckoutLoading(false);
    }
  };

  const validate = (): Record<string, string> => {
    const errs: Record<string, string> = {};
    if (!formData.companyName.trim()) errs.companyName = 'Company name is required.';
    if (!formData.companyNumber.trim()) {
      errs.companyNumber = 'Company number is required.';
    } else if (formData.companyNumber.trim().length !== 8) {
      errs.companyNumber = 'Company number must be exactly 8 characters.';
    }
    if (!formData.requestorEmail.trim()) {
      errs.requestorEmail = 'Email address is required.';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.requestorEmail)) {
      errs.requestorEmail = 'Please enter a valid email address.';
    }
    return errs;
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }
    setErrors({});
    setLoading(true);
    setError('');

    try {
      const response = await fetch('/api/compliance-bundle', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok && data.ok) {
        setSuccess(true);
        setBundleId(data.bundleId);
        setCompanyData(data.company);
        setComplianceData(data.compliance);
        toast.success(data.message || 'Compliance data retrieved successfully!');

        // Reset form
        setFormData({
          companyName: '',
          companyNumber: '',
          requestorName: '',
          requestorEmail: '',
          bundleType: 'full',
        });
      } else {
        setError(data.error || 'Failed to submit form. Please try again.');
        toast.error(data.error || 'Submission failed');
      }
    } catch (err) {
      console.error('Error submitting form:', err);
      setError('Network error. Please check your connection and try again.');
      toast.error('Network error occurred');
    } finally {
      setLoading(false);
    }
  };

  const getRiskColor = (riskLevel: string) => {
    switch (riskLevel) {
      case 'high': return 'bg-red-100 border-red-300 text-red-800';
      case 'medium': return 'bg-orange-100 border-orange-300 text-orange-800';
      case 'low': return 'bg-yellow-100 border-yellow-300 text-yellow-800';
      default: return 'bg-green-100 border-green-300 text-green-800';
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'overdue': return 'bg-red-100 border-red-300 text-red-800';
      case 'warning': return 'bg-orange-100 border-orange-300 text-orange-800';
      default: return 'bg-green-100 border-green-300 text-green-800';
    }
  };

  /**
   * Safely format date, handling 'N/A' and invalid dates
   */
  const formatDate = (dateString: string): string => {
    if (!dateString || dateString === 'N/A') {
      return 'Not available';
    }

    try {
      const date = new Date(dateString);
      if (isNaN(date.getTime())) {
        return 'Not available';
      }
      return date.toLocaleDateString('en-GB');
    } catch {
      return 'Not available';
    }
  };

  /**
   * Check if deadline data is available
   */
  const isDeadlineAvailable = (daysUntilDue: number, dueDate: string): boolean => {
    return daysUntilDue !== 999 && dueDate !== 'N/A';
  };

  if (success && companyData && complianceData) {
    return (
      <div className="min-h-screen bg-[#F8F8F8]">
        <SEO title="Compliance Bundle" description="Your Companies House compliance report — filing deadlines, overdue status, and automated monitoring for your company." />
        <MainNav />
        <div className="py-8 px-4">
        <div className="max-w-4xl mx-auto space-y-6">
          {/* Header */}
          <Card className="bg-white border-[#1A1A1A]/10">
            <CardHeader>
              <div className="flex items-start justify-between">
                <div>
                  <CardTitle className="text-2xl text-[#1A1A1A] mb-2">{companyData.name}</CardTitle>
                  <CardDescription className="text-gray-600">
                    Company No: {companyData.number} • Status: {companyData.status}
                  </CardDescription>
                  <p className="text-sm text-gray-500 mt-1">Bundle Reference: <span className="font-mono text-[#C9A64A]">{bundleId}</span></p>
                </div>
                <div className={`px-4 py-2 rounded-lg border ${getRiskColor(complianceData.riskLevel)}`}>
                  <p className="text-sm font-semibold uppercase">{complianceData.riskLevel} Risk</p>
                </div>
              </div>
            </CardHeader>
          </Card>

          {/* Compliance Status */}
          <Card className="bg-white border-[#1A1A1A]/10">
            <CardHeader>
              <CardTitle className="text-xl text-[#1A1A1A]">Compliance Status</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className={`p-4 rounded-lg border ${getStatusColor(complianceData.status)}`}>
                <p className="font-semibold text-lg mb-1 capitalize">{complianceData.status}</p>
                <p className="text-sm">
                  {complianceData.status === 'compliant' && 'All filings are up to date'}
                  {complianceData.status === 'warning' && 'Upcoming deadlines - action required soon'}
                  {complianceData.status === 'overdue' && 'Immediate action required - filings overdue'}
                </p>
              </div>

              {/* Filing Deadlines */}
              <div className="grid md:grid-cols-2 gap-4">
                {/* Accounts */}
                {isDeadlineAvailable(complianceData.accounts.daysUntilDue, complianceData.accounts.nextDue) ? (
                  <div className={`p-4 rounded-lg border ${complianceData.accounts.overdue ? 'bg-red-50 border-red-200' : 'bg-blue-50 border-blue-200'}`}>
                    <p className="font-semibold text-sm mb-2 flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Annual Accounts
                    </p>
                    <p className={`text-lg font-semibold ${complianceData.accounts.overdue ? 'text-red-700' : 'text-blue-700'}`}>
                      {complianceData.accounts.overdue ? `${Math.abs(complianceData.accounts.daysUntilDue)} days overdue` : `Due in ${complianceData.accounts.daysUntilDue} days`}
                    </p>
                    <p className="text-sm text-gray-600 mt-1">Due: {formatDate(complianceData.accounts.nextDue)}</p>
                  </div>
                ) : (
                  <div className="p-4 rounded-lg border bg-gray-50 border-gray-200">
                    <p className="font-semibold text-sm mb-2 flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Annual Accounts
                    </p>
                    <p className="text-sm text-gray-600">No accounts data available from Companies House</p>
                  </div>
                )}

                {/* Confirmation Statement */}
                {complianceData.confirmationStatement && isDeadlineAvailable(complianceData.confirmationStatement.daysUntilDue, complianceData.confirmationStatement.nextDue) ? (
                  <div className={`p-4 rounded-lg border ${complianceData.confirmationStatement.overdue ? 'bg-red-50 border-red-200' : 'bg-blue-50 border-blue-200'}`}>
                    <p className="font-semibold text-sm mb-2 flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Confirmation Statement
                    </p>
                    <p className={`text-lg font-semibold ${complianceData.confirmationStatement.overdue ? 'text-red-700' : 'text-blue-700'}`}>
                      {complianceData.confirmationStatement.overdue ? `${Math.abs(complianceData.confirmationStatement.daysUntilDue)} days overdue` : `Due in ${complianceData.confirmationStatement.daysUntilDue} days`}
                    </p>
                    <p className="text-sm text-gray-600 mt-1">Due: {formatDate(complianceData.confirmationStatement.nextDue)}</p>
                  </div>
                ) : complianceData.confirmationStatement ? (
                  <div className="p-4 rounded-lg border bg-gray-50 border-gray-200">
                    <p className="font-semibold text-sm mb-2 flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Confirmation Statement
                    </p>
                    <p className="text-sm text-gray-600">No confirmation statement data available</p>
                  </div>
                ) : null}
              </div>
            </CardContent>
          </Card>

          {/* Overdue Filings */}
          {complianceData.overdueFilings && complianceData.overdueFilings.length > 0 && (
            <Card className="bg-white border-red-300">
              <CardHeader>
                <CardTitle className="text-xl text-red-800 flex items-center gap-2">
                  <AlertCircle className="w-5 h-5" />
                  Overdue Filings
                </CardTitle>
                <CardDescription className="text-red-600">
                  Immediate action required to avoid additional penalties
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {complianceData.overdueFilings.map((filing, idx) => (
                  <div key={idx} className="p-4 bg-red-50 border border-red-200 rounded-lg">
                    <div className="flex items-start justify-between mb-2">
                      <div>
                        <p className="font-semibold text-red-900">{filing.description}</p>
                        <p className="text-sm text-red-700">
                          Due: {formatDate(filing.dueDate)} ({filing.daysOverdue} days overdue)
                        </p>
                      </div>
                      <div className="text-right">
                        <p className="text-lg font-bold text-red-800">£{filing.penaltyRisk.toLocaleString()}</p>
                        <p className="text-xs text-red-600">penalty risk</p>
                      </div>
                    </div>
                  </div>
                ))}
              </CardContent>
            </Card>
          )}

          {/* Penalties */}
          {complianceData.penalties && complianceData.penalties.length > 0 && (
            <Card className="bg-white border-orange-300">
              <CardHeader>
                <CardTitle className="text-xl text-orange-800">Estimated Penalties</CardTitle>
                <CardDescription className="text-orange-600">
                  Current or potential late filing penalties
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {complianceData.penalties.map((penalty, idx) => (
                  <div key={idx} className="p-4 bg-orange-50 border border-orange-200 rounded-lg flex items-center justify-between">
                    <p className="text-sm text-orange-900">{penalty.description}</p>
                    <p className="text-xl font-bold text-orange-800">£{penalty.estimated.toLocaleString()}</p>
                  </div>
                ))}
                <div className="p-3 bg-orange-100 border border-orange-300 rounded-lg">
                  <p className="text-sm font-semibold text-orange-900">
                    Total Estimated Penalties: £{complianceData.penalties.reduce((sum, p) => sum + p.estimated, 0).toLocaleString()}
                  </p>
                </div>
              </CardContent>
            </Card>
          )}

          {/* Protection status / CTA */}
          {monitored ? (
            <Card className="bg-green-50 border-green-300">
              <CardContent className="pt-6">
                <div className="flex items-start gap-4 mb-4">
                  <ShieldCheck className="w-8 h-8 text-green-600 flex-shrink-0 mt-0.5" />
                  <div>
                    <p className="text-sm font-semibold text-green-700 uppercase tracking-wide">Protection active</p>
                    <h2 className="text-xl font-bold text-green-900 mt-0.5">
                      {companyData.name} is being monitored
                    </h2>
                    <p className="text-sm text-green-700 mt-1">
                      You'll receive alerts before any compliance deadlines are missed.
                    </p>
                  </div>
                </div>
                <Button
                  onClick={() => {
                    setSuccess(false);
                    setCompanyData(null);
                    setComplianceData(null);
                    setMonitored(false);
                  }}
                  variant="outline"
                  className="border-green-400 text-green-800 hover:bg-green-100"
                >
                  Check Another Company
                </Button>
              </CardContent>
            </Card>
          ) : (
            <Card className="bg-white border-[#1A1A1A]/10">
              <CardContent className="pt-6 space-y-4">
                <div>
                  <h3 className="text-lg font-semibold text-[#1A1A1A]">Activate monitoring</h3>
                  <p className="text-sm text-gray-600 mt-1">
                    Get automatic alerts before filing deadlines for {companyData.name}. £3/month, cancel anytime.
                  </p>
                </div>
                <Button
                  onClick={handleActivate}
                  disabled={checkoutLoading}
                  className="w-full bg-[#C9A64A] hover:bg-[#B8954A] text-white disabled:opacity-50"
                >
                  {checkoutLoading ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Redirecting to checkout…
                    </>
                  ) : (
                    <>
                      <ShieldCheck className="w-4 h-4 mr-2" />
                      Activate Protection — £3/mo
                    </>
                  )}
                </Button>
                <div className="flex gap-3">
                  <Button
                    onClick={() => {
                      setSuccess(false);
                      setCompanyData(null);
                      setComplianceData(null);
                    }}
                    variant="outline"
                    className="flex-1 border-[#1A1A1A]/20 hover:bg-gray-100"
                  >
                    Check Another Company
                  </Button>
                  <Button
                    onClick={() => setLocation('/fineguard')}
                    variant="outline"
                    className="flex-1 border-[#1A1A1A]/20 hover:bg-gray-100"
                  >
                    <ArrowLeft className="w-4 h-4 mr-2" />
                    Back to FineGuard
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}
        </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8F8F8]">
      <SEO title="Compliance Bundle" description="Request a comprehensive Companies House compliance report. Get filing deadlines, overdue status, and automated monitoring for your company." />
      <MainNav />
      <div className="py-12 px-4">
      <div className="max-w-2xl mx-auto">
        <div className="mb-8 text-center">
          <h1 className="text-4xl font-bold text-[#1A1A1A] mb-4">Compliance Bundle Request</h1>
          <p className="text-gray-600 text-lg">
            Get your comprehensive Companies House compliance report
          </p>
        </div>

        <Card className="bg-white border-[#1A1A1A]/10">
          <CardHeader>
            <CardTitle className="text-2xl text-[#1A1A1A]">Request Compliance Bundle</CardTitle>
            <CardDescription className="text-gray-600">
              Provide your company information to receive a detailed compliance bundle
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-6">
              {error && (
                <Alert variant="destructive" className="bg-red-50 border-red-200">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>{error}</AlertDescription>
                </Alert>
              )}

              {/* Company Information */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold text-[#1A1A1A] border-b border-gray-200 pb-2">
                  Company Information
                </h3>

                <div className="space-y-2">
                  <Label htmlFor="companyName" className="text-gray-700">
                    Company Name <span className="text-red-500">*</span>
                  </Label>
                  <Input
                    id="companyName"
                    value={formData.companyName}
                    onChange={(e) => { setFormData({ ...formData, companyName: e.target.value }); if (errors.companyName) setErrors(prev => ({ ...prev, companyName: '' })); }}
                    className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]"
                    placeholder="Your Company Ltd"
                  />
                  {errors.companyName && <p className="text-red-400 text-xs mt-1">{errors.companyName}</p>}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="companyNumber" className="text-gray-700">
                    Companies House Number <span className="text-red-500">*</span>
                  </Label>
                  <Input
                    id="companyNumber"
                    value={formData.companyNumber}
                    onChange={(e) => { setFormData({ ...formData, companyNumber: e.target.value }); if (errors.companyNumber) setErrors(prev => ({ ...prev, companyNumber: '' })); }}
                    className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]"
                    placeholder="12345678"
                    maxLength={8}
                  />
                  {errors.companyNumber ? (
                    <p className="text-red-400 text-xs mt-1">{errors.companyNumber}</p>
                  ) : (
                    <p className="text-sm text-gray-500">8-digit company registration number</p>
                  )}
                </div>
              </div>

              {/* Contact Information */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold text-[#1A1A1A] border-b border-gray-200 pb-2">
                  Contact Information
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <Label htmlFor="requestorName" className="text-gray-700">
                      Your Name
                    </Label>
                    <Input
                      id="requestorName"
                      value={formData.requestorName}
                      onChange={(e) => setFormData({ ...formData, requestorName: e.target.value })}
                      className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]"
                      placeholder="John Doe"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="requestorEmail" className="text-gray-700">
                      Email Address <span className="text-red-500">*</span>
                    </Label>
                    <Input
                      id="requestorEmail"
                      type="email"
                      value={formData.requestorEmail}
                      onChange={(e) => { setFormData({ ...formData, requestorEmail: e.target.value }); if (errors.requestorEmail) setErrors(prev => ({ ...prev, requestorEmail: '' })); }}
                      className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]"
                      placeholder="john@company.co.uk"
                    />
                    {errors.requestorEmail && <p className="text-red-400 text-xs mt-1">{errors.requestorEmail}</p>}
                  </div>
                </div>
              </div>

              {/* Bundle Type */}
              <div className="space-y-2">
                <Label htmlFor="bundleType" className="text-gray-700">
                  Bundle Type
                </Label>
                <Select
                  value={formData.bundleType}
                  onValueChange={(value) => setFormData({ ...formData, bundleType: value })}
                >
                  <SelectTrigger className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]">
                    <SelectValue placeholder="Select bundle type" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="full">
                      <div className="flex flex-col items-start">
                        <span className="font-semibold">Full Compliance Bundle</span>
                        <span className="text-sm text-gray-500">Complete report with all filings</span>
                      </div>
                    </SelectItem>
                    <SelectItem value="basic">
                      <div className="flex flex-col items-start">
                        <span className="font-semibold">Basic Report</span>
                        <span className="text-sm text-gray-500">Essential compliance information only</span>
                      </div>
                    </SelectItem>
                    <SelectItem value="custom">
                      <div className="flex flex-col items-start">
                        <span className="font-semibold">Custom Bundle</span>
                        <span className="text-sm text-gray-500">We'll contact you for requirements</span>
                      </div>
                    </SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                <div className="flex gap-3">
                  <FileText className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
                  <div className="text-sm text-blue-800">
                    <p className="font-semibold mb-1">What You'll Receive:</p>
                    <ul className="space-y-1">
                      <li>• Current filing status from Companies House</li>
                      <li>• List of overdue or upcoming deadlines</li>
                      <li>• Automated compliance calendar</li>
                      <li>• Mobile alerts for important dates</li>
                    </ul>
                  </div>
                </div>
              </div>

              <div className="flex gap-3">
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setLocation('/fineguard')}
                  className="flex-1 border-gray-300 hover:bg-gray-100"
                >
                  Cancel
                </Button>
                <Button
                  type="submit"
                  disabled={loading}
                  className={`flex-1 bg-[#C9A64A] hover:bg-[#B8954A] text-white ${loading ? 'opacity-60 cursor-not-allowed' : ''}`}
                >
                  {loading ? (
                    <span className="flex items-center gap-2">
                      <span className="w-4 h-4 rounded-full border-2 border-white/40 border-t-white animate-spin" />
                      Submitting…
                    </span>
                  ) : 'Request Bundle'}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>

        <p className="text-center text-gray-500 text-sm mt-6">
          Your information is secure and will only be used to generate your compliance bundle
        </p>
      </div>
      </div>
    </div>
  );
}

import { useState, FormEvent } from 'react';
import { useLocation } from 'wouter';
import { Button } from '@/components/ui/button';
import LegalNav from '@/components/LegalNav';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Loader2, CheckCircle, AlertCircle, ArrowLeft, AlertTriangle } from 'lucide-react';
import { toast } from 'sonner';

export default function IntakeSheet() {
  const [, setLocation] = useLocation();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [matterRef, setMatterRef] = useState('');
  const [urgencyLevel, setUrgencyLevel] = useState('');
  const [error, setError] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    clientPhone: '',
    matterType: '',
    urgency: '',
    description: '',
    claimValue: '',
  });

  const validate = (): Record<string, string> => {
    const errs: Record<string, string> = {};
    if (!formData.clientName.trim()) errs.clientName = 'Client name is required.';
    if (!formData.clientEmail.trim()) {
      errs.clientEmail = 'Client email is required.';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.clientEmail)) {
      errs.clientEmail = 'Please enter a valid email address.';
    }
    if (!formData.matterType) errs.matterType = 'Matter type is required.';
    if (!formData.description.trim()) {
      errs.description = 'Matter description is required.';
    } else if (formData.description.trim().length < 20) {
      errs.description = 'Description must be at least 20 characters.';
    }
    return errs;
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }
    setErrors({});
    setLoading(true);
    setError('');

    try {
      const response = await fetch('/api/intake', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok && data.ok) {
        setSuccess(true);
        setMatterRef(data.matterRef);
        setUrgencyLevel(data.urgency);
        toast.success(data.message || 'Matter intake recorded successfully!');

        // Reset form
        setFormData({
          clientName: '',
          clientEmail: '',
          clientPhone: '',
          matterType: '',
          urgency: '',
          description: '',
          claimValue: '',
        });
      } else {
        setError(data.error || 'Failed to submit form. Please try again.');
        toast.error(data.error || 'Submission failed');
      }
    } catch (err) {
      console.error('Error submitting form:', err);
      setError('Network error. Please check your connection and try again.');
      toast.error('Network error occurred');
    } finally {
      setLoading(false);
    }
  };

  const getUrgencyColor = (urgency: string) => {
    switch (urgency.toLowerCase()) {
      case 'critical':
        return 'bg-red-500/20 border-red-500/50 text-red-400';
      case 'high':
        return 'bg-orange-500/20 border-orange-500/50 text-orange-400';
      case 'medium':
        return 'bg-yellow-500/20 border-yellow-500/50 text-yellow-400';
      case 'low':
        return 'bg-green-500/20 border-green-500/50 text-green-400';
      default:
        return 'bg-gray-500/20 border-gray-500/50 text-gray-400';
    }
  };

  if (success) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-[#0B0C10] via-[#1A1D28] to-[#0B0C10]">
        <LegalNav active="intake" />
        <div className="flex items-center justify-center p-4 py-20">
          <Card className="w-full max-w-md bg-[#13151C] border-[#2A2D3A]">
            <CardHeader className="text-center">
              <div className="mx-auto mb-4 w-16 h-16 bg-cyan-500/20 rounded-full flex items-center justify-center">
                <CheckCircle className="w-8 h-8 text-cyan-400" />
              </div>
              <CardTitle className="text-2xl text-white">Intake Recorded!</CardTitle>
              <CardDescription className="text-gray-400">
                Your client matter has been successfully registered
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4 text-center">
              <div className="p-5 bg-[#1A1D28] border border-[#2A2D3A] rounded-lg">
                <p className="text-sm text-gray-400 mb-2">Matter Reference</p>
                <p className="text-3xl font-mono font-bold text-yellow-400">{matterRef}</p>
              </div>

              {urgencyLevel && (
                <div className={`p-3 rounded-lg border ${getUrgencyColor(urgencyLevel)}`}>
                  <div className="flex items-center justify-center gap-2">
                    <AlertTriangle className="w-4 h-4" />
                    <span className="font-semibold">Priority: {urgencyLevel.toUpperCase()}</span>
                  </div>
                </div>
              )}

              <p className="text-gray-300">
                Your matter has been registered. A solicitor will contact you within 24 hours.
              </p>

              <div className="pt-1 border-t border-[#2A2D3A]">
                <p className="text-xs text-gray-500 mb-3">Legal Suite</p>
                <Button
                  onClick={() => setLocation('/clerk-dashboard')}
                  className="w-full bg-gradient-to-r from-cyan-500 to-blue-500 hover:from-cyan-600 hover:to-blue-600 text-white"
                >
                  Track your matter status with your clerk →
                </Button>
              </div>

              <Button
                onClick={() => setSuccess(false)}
                variant="outline"
                className="w-full bg-[#1A1D28] border-[#2A2D3A] hover:bg-[#252830] text-white"
              >
                Submit Another Matter
              </Button>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#0B0C10] via-[#1A1D28] to-[#0B0C10]">
      <LegalNav active="intake" />
      <div className="py-12 px-4">
      <div className="max-w-3xl mx-auto">
        <div className="mb-8 text-center">
          <h1 className="text-4xl font-bold text-white mb-4">Client Matter Intake Sheet</h1>
          <p className="text-gray-400 text-lg">
            Secure and confidential matter information collection
          </p>
        </div>

        <Card className="bg-[#13151C] border-[#2A2D3A]">
          <CardHeader>
            <CardTitle className="text-2xl text-white">New Matter Intake</CardTitle>
            <CardDescription className="text-gray-400">
              Please provide complete information about the client matter
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-6">
              {error && (
                <Alert variant="destructive" className="bg-red-500/10 border-red-500/50">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>{error}</AlertDescription>
                </Alert>
              )}

              {/* Client Information */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold text-white border-b border-[#2A2D3A] pb-2">
                  Client Information
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2 md:col-span-2">
                    <Label htmlFor="clientName" className="text-gray-300">
                      Client Name <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      id="clientName"
                      value={formData.clientName}
                      onChange={(e) => { setFormData({ ...formData, clientName: e.target.value }); if (errors.clientName) setErrors(prev => ({ ...prev, clientName: '' })); }}
                      className="bg-[#1A1D28] border-[#2A2D3A] text-white focus:border-cyan-500"
                      placeholder="Full legal name"
